/**
 * Implementation of a Min Priority Queue using a binary heap.
 * Stores elements as [priority, value].
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    peek() {
        return this.heap.length > 0 ? this.heap[0] : null;
    }

    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            // Compare priorities (index 0 of the element array)
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Check left child
            if (leftChildIndex <= lastIndex && 
                this.heap[leftChildIndex][0] < this.heap[smallest][0]) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex <= lastIndex && 
                this.heap[rightChildIndex][0] < this.heap[smallest][0]) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // 1. Build Adjacency List
    const adj = Array(n).fill(0).map(() => []);
    let maxWeight = 0;
    for (const [u, v, w] of edges) {
        adj[u].push({ neighbor: v, weight: w });
        adj[v].push({ neighbor: u, weight: w });
        if (w > maxWeight) {
            maxWeight = w;
        }
    }

    // If there are no edges and source != target, path is impossible.
    if (edges.length === 0 && source !== target) {
        return -1;
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges 
     * when the threshold is T.
     * @param {number} T - The threshold weight.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const canReach = (T) => {
        // dist[i] stores the minimum number of heavy edges required to reach node i.
        const INF = k + 1; // Since we only care if it's <= k, k+1 serves as infinity.
        const dist = Array(n).fill(INF);

        // Priority Queue stores [heavy_edge_count, node]
        const pq = new MinPriorityQueue();

        dist[source] = 0;
        pq.enqueue([0, source]);

        while (!pq.isEmpty()) {
            const [current_c, u] = pq.dequeue();

            if (current_c > dist[u]) {
                continue;
            }

            if (u === target) {
                // We found the minimum heavy edge path to target, and it is <= k 
                // because of the check when we enqueue/update dist.
                return true;
            }

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const w = edge.weight;

                // Cost: 1 if heavy (w > T), 0 if light (w <= T)
                const cost = (w > T) ? 1 : 0;

                const new_c = current_c + cost;

                if (new_c < dist[v]) {
                    dist[v] = new_c;

                    // Optimization: Only push if the new count doesn't exceed k
                    if (new_c <= k) {
                        pq.enqueue([new_c, v]);
                    }
                }
            }
        }

        return dist[target] <= k;
    };

    // 2. Binary Search on the threshold T
    // Search range: [L, R]. L=0 (minimum possible threshold). R=10^9 (maximum possible weight).
    let L = 0;
    // Since weights are up to 10^9, we use 10^9 as the upper bound.
    let R = 10**9; 
    let min_threshold = -1;

    while (L <= R) {
        // Use Math.floor for integer division
        const M = Math.floor((L + R) / 2);

        if (canReach(M)) {
            // M works. Store it as a potential answer and try for a smaller threshold.
            min_threshold = M;
            R = M - 1;
        } else {
            // M is too small (too many heavy edges). Increase threshold.
            L = M + 1;
        }
    }

    return min_threshold;
}

