package main

import (
	"container/heap"
	"math"
)

// Edge struct to store graph connectivity
type Edge struct {
	neighbor int64
	weight   int64
}

// State struct for Dijkstra's algorithm priority queue
type State struct {
	heavyCount int64 // Priority: minimum number of heavy edges used so far
	node       int64
}

// MinHeap implements heap.Interface for State, prioritizing smaller heavyCount
type MinHeap []*State

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i].heavyCount < h[j].heavyCount }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MinHeap) Push(x interface{}) {
	*h = append(*h, x.(*State))
}

func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(n int64, edges [][]int64, source int64, target int64, k int64) int64 {
	if source == target {
		return 0
	}

	// 1. Build Adjacency List
	adj := make([][]Edge, n)
	maxWeight := int64(0)

	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		adj[u] = append(adj[u], Edge{neighbor: v, weight: w})
		adj[v] = append(adj[v], Edge{neighbor: u, weight: w})
		if w > maxWeight {
			maxWeight = w
		}
	}

	// Check initial connectivity (if no path exists even with infinite threshold)
	// A simple BFS/DFS can check if target is reachable from source, but Dijkstra handles this implicitly.

	// Checks if a path exists from source to target using at most k heavy edges 
	// when the threshold is T.
	canReach := func(T int64) bool {
		// dist[i] stores the minimum number of heavy edges required to reach node i.
		// Initialize to K+1, which serves as infinity since we only care if it's <= K.
		const INF int64 = math.MaxInt64
		dist := make([]int64, n)
		for i := range dist {
			dist[i] = INF
		}

		// Priority Queue initialized
		pq := &MinHeap{}
		heap.Init(pq)

		dist[source] = 0
		heap.Push(pq, &State{heavyCount: 0, node: source})

		for pq.Len() > 0 {
			current := heap.Pop(pq).(*State)
			current_c := current.heavyCount
			u := current.node

			if current_c > dist[u] {
				continue
			}

			if u == target {
				// Since we found the minimum heavy edge path, and we only push states
				// where heavyCount <= k, this path is valid.
				return true
			}

			for _, edge := range adj[u] {
				v := edge.neighbor
				w := edge.weight

				// Cost: 1 if heavy (w > T), 0 if light (w <= T)
				cost := int64(0)
				if w > T {
					cost = 1
				}

				new_c := current_c + cost

				if new_c < dist[v] && new_c <= k {
					dist[v] = new_c
					heap.Push(pq, &State{heavyCount: new_c, node: v})
				}
			}
		}

		return false
	}

	// 2. Binary Search on the threshold T
	// Search range: [L, R]. L=0. R=maxWeight (or 10^9 if maxWeight is 0 and edges exist).
	// Since weights are positive (>= 1), maxWeight >= 1 if edges exist.

	L := int64(0)
	R := maxWeight 

	// If there are no edges, we only succeed if source == target (handled above).
	if len(edges) == 0 && source != target {
		return -1
	}

	// We must also check the upper bound 10^9 if maxWeight wasn't properly set (e.g., if weights were 0, but constraints say W >= 1)
	// Since constraints guarantee 1 <= W_i <= 10^9, maxWeight covers the necessary upper bound.

	minThreshold := int64(-1)

	for L <= R {
		M := L + (R-L)/2 // Safe way to calculate floor((L+R)/2)

		if canReach(M) {
			// M works. Store it and try for a smaller threshold.
			minThreshold = M
			R = M - 1
		} else {
			// M is too small (too many heavy edges). Increase threshold.
			L = M + 1
		}
	}

	return minThreshold
}
