	canReach := func(T int64) bool {
		// dist[i] stores the minimum number of heavy edges required to reach node i.
		const INF = math.MaxInt64 / 2 // A sufficiently large number
		dist := make([]int64, n)
		for i := range dist {
			dist[i] = INF
		}

		pq := make(PriorityQueue, 0)
		heap.Init(&pq)

		dist[source] = 0
		heap.Push(&pq, &Item{count: 0, node: source})

		for pq.Len() > 0 {
			item := heap.Pop(&pq).(*Item)
			current_c := item.count
			u := item.node

			if current_c > dist[u] {
				continue
			}

			if u == target {
				// Since Dijkstra's guarantees finding the minimum path first,
				// if we reach target, and we ensured dist[u] <= k before processing,
